patch:
--- a/controller_fsm.vhd
+++ b/controller_fsm.vhd
@@ -12,7 +12,7 @@
     state_next : out std_logic_vector(2 downto 0)
   );

-  process(state_curr, reset)
+  process(state_curr, reset, input_signal)
   begin
     if reset = '1' then
       state_next <= "000";

before_code:
library ieee;
use ieee.std_logic_1164.all;

entity controller_fsm is
  port (
    clk : in std_logic;
    reset : in std_logic;
    input_signal : in std_logic;
    state_curr : in std_logic_vector(2 downto 0);
    state_next : out std_logic_vector(2 downto 0)
  );
end entity;

architecture rtl of controller_fsm is
begin
  process(state_curr, reset)
  begin
    if reset = '1' then
      state_next <= "000";
    elsif state_curr = "001" and input_signal = '1' then
      state_next <= "010";
    else
      state_next <= state_curr;
    end if;
  end process;
end architecture;

after_code:
library ieee;
use ieee.std_logic_1164.all;

entity controller_fsm is
  port (
    clk : in std_logic;
    reset : in std_logic;
    input_signal : in std_logic;
    state_curr : in std_logic_vector(2 downto 0);
    state_next : out std_logic_vector(2 downto 0)
  );
end entity;

architecture rtl of controller_fsm is
begin
  process(state_curr, reset, input_signal)
  begin
    if reset = '1' then
      state_next <= "000";
    elsif state_curr = "001" and input_signal = '1' then
      state_next <= "010";
    else
      state_next <= state_curr;
    end if;
  end process;
end architecture;
